(()=>{const $=s=>document.querySelector(s);const $$=s=>Array.from(document.querySelectorAll(s));const roles=[['Planner','turns intent into a loop contract'],['Generator','produces bounded artifacts'],['Evaluator','scores function, craft, originality, safety'],['Verifier','checks replay and evidence gates'],['Archivist','writes Chronicle-ready state']];const gates=['contract','roles','trace','restart','score','evidence','chronicle'];const presets={proofPage:'Build a public-safe proof page that shows whether an autonomous AI work result deserves stakeholder review.',leanProof:'Package a Lean/Lake theorem-proving attempt with pinned toolchain, replay logs, proof-state trace, and no hidden sorry/admit.',securityPatch:'Turn a defensive patch proposal into a review-ready Evidence Docket with tests, rollback, and no unsafe external action.',marketBrief:'Produce a claim-bounded market brief with sources, uncertainty, contradiction register, and decision boundary.'};let state={cycle:0,proof:0,events:[],harness:100,done:false,verdict:'AWAITING_CONTRACT',bottleneck:'contract',seed:173};function hash(s){let h=2166136261;for(let i=0;i<s.length;i++){h^=s.charCodeAt(i);h=Math.imul(h,16777619)}return ('00000000'+(h>>>0).toString(16)).slice(-8).toUpperCase()}function initStars(){const c=document.querySelector('.stars');if(!c)return;const ctx=c.getContext('2d');let w,h,pts=[];function reset(){w=c.width=innerWidth;h=c.height=innerHeight;pts=Array.from({length:120},()=>({x:Math.random()*w,y:Math.random()*h,r:1+Math.random()*3,s:.15+Math.random()*.55,c:Math.random()>.7?'#ffe67b':Math.random()>.5?'#70ffd5':'#7aa6ff'}))}function draw(){ctx.clearRect(0,0,w,h);for(const p of pts){p.y-=p.s;if(p.y<-20)p.y=h+20;ctx.beginPath();ctx.fillStyle=p.c;ctx.globalAlpha=.35;ctx.arc(p.x,p.y,p.r,0,7);ctx.fill();ctx.globalAlpha=.16;ctx.fillRect(p.x-.5,p.y,p.r*.25,32)}requestAnimationFrame(draw)}addEventListener('resize',reset);reset();draw()}function renderRoles(){const grid=$('#roleGrid');grid.innerHTML=roles.map((r,i)=>`<div class="role ${i===state.cycle%roles.length&&!state.done?'active':''}"><b>${r[0]}</b><span>${r[1]}</span></div>`).join('')}function gateStatus(){return gates.map((g,i)=>({name:g,pass:state.proof>=((i+1)*14)}))}function compute(){const strict=+$('#strictness').value,budget=+$('#budget').value,restart=+$('#restart').value;const posture=$('#loopPosture').value;const bonus={institutional:8,frontier:4,austere:10,review:12}[posture]||0;state.proof=Math.min(100,Math.max(0,Math.round(state.cycle*13+bonus+restart*.08+strict*.05-budget*.02)));state.harness=Math.max(18,Math.round(100-state.cycle*9-(posture==='austere'?18:0)));const next=gateStatus().find(g=>!g.pass);state.bottleneck=next?next.name:'human review';state.done=state.proof>=96;state.verdict=state.done?'HUMAN_REVIEW_READY':state.proof>=72?'EVIDENCE_DOCKET_READY':state.proof>=42?'RUNNING_TRACE_VALID':'LOOP_IN_PROGRESS'}function eventLine(kind,msg){const root=hash(JSON.stringify({kind,msg,cycle:state.cycle,seed:state.seed,events:state.events.length}));return {cycle:state.cycle,kind,msg,root,time:new Date().toISOString().replace(/\.\d+Z$/,'Z')}}function addEvent(kind,msg){state.events.push(eventLine(kind,msg));if(state.events.length>80)state.events=state.events.slice(-80)}function advance(auto=false){if(state.done&&!auto)return;state.cycle++;const stage=roles[(state.cycle-1)%roles.length][0];const messages={Planner:'Loop contract negotiated: objective, done condition, budget, risk, rollback, and forbidden actions written.',Generator:'Bounded artifact emitted under role charter; no external action and no wallet authority requested.',Evaluator:'Score vector updated: function, craft, originality, safety, replay, evidence, and proof debt.',Verifier:'Replay/evidence gate checked; unsupported claims returned to trace rather than Chronicle.',Archivist:'Accepted state compressed into Chronicle-ready memory; rejected work preserved as warning.'};addEvent(stage,messages[stage]);if(stage==='Verifier'&&$('#restart').value>60&&state.cycle<7){addEvent('Restart','Loop discarded a weak branch, preserved the reason, and restarted from contract without losing trace.')}compute();render()}function render(){renderRoles();$('#cycleCount').textContent=state.cycle;$('#heroCycles').textContent=state.cycle;$('#proofScore').textContent=state.proof;$('#traceCount').textContent=state.events.length;$('#harnessWeight').textContent=state.harness;$('#bottleneck').textContent=state.bottleneck;$('#heroDocket').textContent=state.proof>=72?1:0;$('#donePct').textContent=state.proof+'%';$('#stateName').textContent=state.done?'HUMAN_REVIEW_READY':state.proof>=72?'DOCKET_SEALED':'RUNNING';$('#traceRoot').textContent='LOOP-'+hash(state.events.map(e=>e.root).join('|')||'empty').slice(0,8);$('#verdict').textContent=state.verdict;$('#traceHint').textContent=state.events.length?state.events.length+' events appended':'No trace yet.';$('#traceLog').textContent=state.events.length?state.events.map(e=>`${String(e.cycle).padStart(2,'0')} ${e.kind.toUpperCase()} ${e.root}\n${e.msg}`).join('\n\n'):'Press “Run proof loop” to begin.';const deg=Math.round(state.proof*3.6);$('.ring-score').style.background=`conic-gradient(var(--mint) ${deg}deg, rgba(255,255,255,.12) ${deg}deg)`;$('#activePath').style.strokeDasharray=`${state.proof*10} 1000`;$('#decisionTitle').textContent=state.done?'Loop receipt ready for human review.':state.proof>=72?'Evidence Docket is sealed; human review remains.':state.proof>=42?'Trace is valid; proof still incomplete.':'Contract and role separation still forming.';$('#decisionText').textContent=state.done?'The loop has contract, roles, trace, restart record, score, evidence, and Chronicle-ready state. It still does not certify external facts or authorize action.':state.proof>=72?'A public-safe docket exists, but final claim promotion waits on human review and replay inspection.':state.proof>=42?'The run is no longer just output. It has a readable trace and evaluator state, but not enough proof for Chronicle.':'The loop has not yet produced enough evidence to advance.';$('#gates').innerHTML=gateStatus().map(g=>`<li><span>${g.name}</span><b>${g.pass?'PASS':'HOLD'}</b></li>`).join('');}function runLoop(){if(!state.events.length)addEvent('Contract','Mission converted into LoopContract with separate roles and explicit stop rule.');for(let i=0;i<8&&!state.done;i++)advance(true);render()}function receipt(){return {schema:'GoalOSLoopReceipt/v1',release:'v47-loop-operating-room',publicSafe:true,browserLocal:true,noWallet:true,noNetwork:true,noUserDataWanted:true,objective:$('#objective').value,missionPreset:$('#missionPreset').value,loopPosture:$('#loopPosture').value,cycles:state.cycle,proofScore:state.proof,verdict:state.verdict,bottleneck:state.bottleneck,harnessWeight:state.harness,gates:gateStatus(),roles:roles.map(([name,obligation])=>({name,obligation})),traceRoot:$('#traceRoot').textContent,events:state.events,claimBoundary:'Review material only; no factual certification, no external action, no settlement, no token operation, no production authority.'}}function download(){const blob=new Blob([JSON.stringify(receipt(),null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='goalos-loop-receipt.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}function copyBrief(){const r=receipt();const txt=`GoalOS Loop Operating Room\nVerdict: ${r.verdict}\nCycles: ${r.cycles}\nProof score: ${r.proofScore}\nTrace root: ${r.traceRoot}\nBottleneck: ${r.bottleneck}\nBoundary: ${r.claimBoundary}`;navigator.clipboard?.writeText(txt)}function bind(){initStars();renderRoles();compute();render();$('#missionPreset').addEventListener('change',e=>{$('#objective').value=presets[e.target.value]||presets.proofPage});for(const id of ['budget','strictness','restart']){$('#'+id).addEventListener('input',e=>{$('#'+id+'Out').textContent=e.target.value;compute();render()})}$('#loopPosture').addEventListener('change',()=>{compute();render()});$('#runLoop').addEventListener('click',runLoop);$('#advanceLoop').addEventListener('click',()=>{if(!state.events.length)addEvent('Contract','Mission converted into LoopContract with separate roles and explicit stop rule.');advance();render()});$('#resetLoop').addEventListener('click',()=>{state={cycle:0,proof:0,events:[],harness:100,done:false,verdict:'AWAITING_CONTRACT',bottleneck:'contract',seed:173};compute();render()});$('#downloadReceipt').addEventListener('click',download);$('#copyBrief').addEventListener('click',copyBrief);$('#copyLoopLaw').addEventListener('click',()=>navigator.clipboard?.writeText('Prompt once. Loop until proof. Contract, roles, trace, restart, score, evidence, Chronicle.'));}if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',bind);else bind();})();